-- Перенос данных с живого MySQL (ntrip.host, база u3523560_gisdata) в PostgreSQL.
-- Запускать ПОСЛЕ sql/schema.sql, один раз, на новой Postgres-базе.
-- Источник: экспорт phpMyAdmin от 2026-06-22.
--
-- Порядок вставки учитывает внешние ключи: users_sync/admins/stations —
-- сначала, затем pg_connections/subscriptions/tours/station_status/station_log.
-- В конце — синхронизация сиквенсов (id вставлены явно, без них следующий
-- INSERT из приложения попытался бы использовать уже занятый id).
--
-- ВАЖНО: в pg_connections.host сейчас значение 'http://mtccom.ru' — это
-- ошибка ввода через форму (PDO/libpq host не принимает схему http://).
-- После миграции зайдите в "Подключения БД" и поправьте на 'mtccom.ru'.

BEGIN;

-- ---------------------------------------------------------------------------
-- users_sync (332 строки, источник истины — mdb, синхронизируется отдельно
-- через bin/sync_mdb_users.php; переносим как снимок на момент миграции)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- admins (1 строка — текущий суперпользователь)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- pg_connections (1 профиль). ВНИМАНИЕ: host = 'http://mtccom.ru' взят как
-- есть из живых данных — это, по всей видимости, ошибка ввода (libpq не
-- принимает схему http:// в host). Поправьте на 'mtccom.ru' после миграции
-- через страницу "Подключения БД".
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- stations (24 станции)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- station_status (24 строки)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- subscriptions (3 строки)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- tours (1 строка)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- station_log (120 строк, история проверок)
-- ---------------------------------------------------------------------------

-- ---------------------------------------------------------------------------
-- Синхронизация сиквенсов (id вставлены явно, без autoincrement)
-- ---------------------------------------------------------------------------
SELECT setval(pg_get_serial_sequence('admins', 'id'), (SELECT COALESCE(MAX(id), 1) FROM admins));
SELECT setval(pg_get_serial_sequence('admin_invites', 'id'), (SELECT COALESCE(MAX(id), 1) FROM admin_invites));
SELECT setval(pg_get_serial_sequence('pg_connections', 'id'), (SELECT COALESCE(MAX(id), 1) FROM pg_connections));
SELECT setval(pg_get_serial_sequence('subscriptions', 'id'), (SELECT COALESCE(MAX(id), 1) FROM subscriptions));
SELECT setval(pg_get_serial_sequence('tours', 'id'), (SELECT COALESCE(MAX(id), 1) FROM tours));
SELECT setval(pg_get_serial_sequence('stations', 'id'), (SELECT COALESCE(MAX(id), 1) FROM stations));
SELECT setval(pg_get_serial_sequence('station_log', 'id'), (SELECT COALESCE(MAX(id), 1) FROM station_log));

COMMIT;
